const now = new Date();
const today = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const dayOfWeek = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][now.getDay()];
const d = now.getDay();
const daysToMon = d === 0 ? 6 : d - 1;
const weekStart = new Date(now - daysToMon * 86400000).toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
return [{ json: { today, dayOfWeek, weekStart } }];

const items = $input.all();
const files = items
  .filter(i => i.json.Key && i.json.Key.endsWith('.md') && (i.json.Size || 0) > 0)
  .map(i => ({ key: i.json.Key, name: i.json.Key.split('/').pop(), sizeKB: Math.round((i.json.Size||0)/1024) }));
const { today, dayOfWeek, weekStart } = $('Set Dates').first().json;
return [{ json: { braindumpFiles: files, braindumpCount: files.length, today, dayOfWeek, weekStart } }];

const items = $input.all();
const { today, dayOfWeek, weekStart, braindumpFiles, braindumpCount } = $('Collect Brain Dumps').first().json;
const thisWeek = items
  .filter(i => {
    const key = i.json.Key || '';
    if (!key.endsWith('.md') || (i.json.Size || 0) === 0) return false;
    const name = key.split('/').pop();
    const m = name.match(/^(\d{4}-\d{2}-\d{2})/);
    return m && m[1] >= weekStart;
  })
  .map(i => ({ key: i.json.Key, name: i.json.Key.split('/').pop() }));
return [{ json: { today, dayOfWeek, weekStart, braindumpFiles, braindumpCount, processedThisWeek: thisWeek, processedCount: thisWeek.length } }];

const { today, weekStart, braindumpFiles, braindumpCount, processedThisWeek, processedCount } = $input.first().json;
let articlesContent = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  articlesContent = buf.toString('utf-8');
} catch(e) {}
const allUrls = articlesContent.split('\n').filter(l => /https?:\/\//.test(l));
const enriched = allUrls.filter(l => l.includes('[title::'));
const unenriched = allUrls.filter(l => !l.includes('[title::'));

let html = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;color:#2c3e50">';
html += `<h1 style="border-bottom:3px solid #9b59b6;padding-bottom:8px">Vault Health Report &mdash; Week of ${weekStart}</h1>`;

// Brain Dumps section
html += '<div style="background:#f4ecf7;border-left:4px solid #9b59b6;padding:12px;margin:16px 0">';
html += `<h2 style="color:#9b59b6;margin-top:0">Brain Dump Files (${braindumpCount} in inbox)</h2>`;
if (braindumpCount === 0) {
  html += '<p style="color:#27ae60">Inbox clear — no brain dumps waiting</p>';
} else {
  html += '<ul>' + braindumpFiles.map(f => `<li><strong>${f.name}</strong> (${f.sizeKB}KB)</li>`).join('') + '</ul>';
  html += `<p style="color:#e67e22"><strong>Warning: ${braindumpCount} file(s) in brain-dumps/ — check processor logs.</strong></p>`;
}
html += '</div>';

// Article queue section
html += '<div style="background:#eaf3fb;border-left:4px solid #3498db;padding:12px;margin:16px 0">';
html += `<h2 style="color:#3498db;margin-top:0">Article Queue (${allUrls.length} total)</h2>`;
html += `<ul><li>Enriched with titles: <strong style="color:#27ae60">${enriched.length}</strong></li>`;
html += `<li>Needs enrichment: <strong style="color:${unenriched.length > 10 ? '#e74c3c' : '#e67e22'}">${unenriched.length}</strong></li></ul>`;
if (unenriched.length > 0) {
  html += '<details><summary>Unenriched URLs</summary><ul>';
  html += unenriched.slice(0, 12).map(l => `<li><code>${l.slice(0,90).replace(/</g,'&lt;')}</code></li>`).join('');
  if (unenriched.length > 12) html += `<li>...and ${unenriched.length - 12} more</li>`;
  html += '</ul></details>';
}
html += '</div>';

// Processed this week
html += '<div style="background:#eafaf1;border-left:4px solid #27ae60;padding:12px;margin:16px 0">';
html += `<h2 style="color:#27ae60;margin-top:0">Processed This Week (${processedCount} files since ${weekStart})</h2>`;
if (processedCount === 0) {
  html += '<p style="color:#e74c3c">No tasks processed this week. Brain dump processor may not be running.</p>';
} else {
  html += '<ul>' + processedThisWeek.slice(0,10).map(f => `<li>${f.name}</li>`).join('');
  if (processedCount > 10) html += `<li>...and ${processedCount - 10} more</li>`;
  html += '</ul>';
}
html += '</div>';

const healthy = braindumpCount === 0 && unenriched.length < 10 && processedCount > 0;
const critical = unenriched.length > 30 || processedCount === 0;
const badge = healthy ? 'HEALTHY' : critical ? 'NEEDS ATTENTION' : 'OK';
html += `<p style="text-align:center;font-size:18px;font-weight:bold">Status: ${badge}</p>`;
html += '<p style="color:#95a5a6;font-size:11px;text-align:center">Generated ' + new Date().toISOString() + '</p></div>';

const subject = `Vault Health: ${badge} | ${braindumpCount} dumps, ${unenriched.length} unenriched, ${processedCount} processed this week`;
return [{ json: { html, subject, today, badge, braindumpCount, unenrichedCount: unenriched.length, processedCount } }];

const j = $input.first().json;
const log = JSON.stringify({
  workflow: 'vault-health-report', run_date: j.today,
  finished_at: new Date().toISOString(), status: 'success',
  badge: j.badge, braindump_count: j.braindumpCount,
  unenriched_articles: j.unenrichedCount, processed_this_week: j.processedCount
}, null, 2);
const buf = Buffer.from(log, 'utf-8');
const logKey = `99_System/logs/vault-health-report-${j.today}.json`;
return [{ json: { logKey }, binary: {
  data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: logKey.split('/').pop(), fileExtension: 'json', fileSize: buf.length }
}}];
